+                if (reason == Boolean.TRUE) {
+                    throw new IOException("Stream is closed");
+                } else {
+                    throw new IOException((IOException)reason);
+                }
+            }
+            while (true) {
+                if (current != null && current.hasRemaining()) {
+                    return current;
+                }
+                if (current == QuicStreamReader.EOF) {
+                    reason = closeReason.get();
